import os
import re

def extract_text_patterns(filepath):
    try:
        with open(filepath, 'rb') as f:
            content = f.read().decode('latin-1', errors='ignore')
            # Look for invoice-related keywords
            invoice_keywords = re.findall(r'[A-Za-z\s]{0,10}(?:invoice|total|amount|vat|tax|due|bill|grand|subtotal)[A-Za-z\s]{0,10}', content, re.IGNORECASE)
