            amounts = re.findall(r'[\$£€]?[0-9]{1,4}[.,][0-9]{2}|[0-9]{1,4}[.,][0-9]{2}[\s]*[\$£€]', content)
            return invoice_keywords, amounts
    except:
        return [], []

